package clock

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"
	"google.golang.org/protobuf/types/known/timestamppb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/clock"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type ClockProxy struct {
	clock.UnimplementedClockServer
	client clock.ClockClient
}

func init() {
	proxyutil.Register(&clock.Clock_ServiceDesc, NewClockProxy)
}
func NewClockProxy(cc grpc.ClientConnInterface) clock.ClockServer {
	return &ClockProxy{client: clock.NewClockClient(cc)}
}
func (p *ClockProxy) Now(ctx context.Context, in *emptypb.Empty) (*timestamppb.Timestamp, error) {
	return proxyutil.ProxyMethod[emptypb.Empty, timestamppb.Timestamp](p.client.Now)(ctx, in)
}
